using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the Open-Meteo weather REST API.
/// Uses constructor injection for HttpClient and ILogger.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current_weather=true";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var weather = doc.RootElement.GetProperty("current_weather");

        return $"Temperature: {weather.GetProperty("temperature")}°C, "
             + $"Wind: {weather.GetProperty("windspeed")} km/h, "
             + $"Code: {weather.GetProperty("weathercode")}";
    }

    [McpServerTool, Description("Get a multi-day temperature forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-16)")] int days = 7,
        CancellationToken cancellationToken = default)
    {
        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var daily = doc.RootElement.GetProperty("daily");
        var dates = daily.GetProperty("time");
        var maxTemps = daily.GetProperty("temperature_2m_max");
        var minTemps = daily.GetProperty("temperature_2m_min");

        var lines = new List<string>();
        for (int i = 0; i < dates.GetArrayLength(); i++)
        {
            lines.Add($"{dates[i]}: {minTemps[i]}°C – {maxTemps[i]}°C");
        }

        return string.Join("\n", lines);
    }
}

